   318→
   319→	// In Terraform v1.1 and earlier we had some confusion about which subsystem
   320→	// of Terraform was the one responsible for substituting in default values
   321→	// for unset module variables, with root module variables being handled in
   322→	// three different places while child module variables were only handled
   323→	// during the Terraform Core graph walk.
   324→	//
   325→	// For Terraform v1.2 and later we rationalized that by having the Terraform
   326→	// Core graph walk always be responsible for selecting defaults regardless
   327→	// of root vs. child module, but unfortunately our earlier accidental
   328→	// misbehavior bled out into the public interface by making the defaults
   329→	// show up in the "vars" map to this function. Those are now correctly
   330→	// omitted (so that the plan file only records the variables _actually_
   331→	// set by the caller) but consumers of the JSON plan format may be depending
   332→	// on our old behavior and so we'll fake it here just in time so that
   333→	// outside consumers won't see a behavior change.
   334→	for name, decl := range decls {
   335→		if _, ok := p.Variables[name]; ok {
   336→			continue
   337→		}
   338→		if val := decl.Default; val != cty.NilVal {
   339→			valJSON, err := ctyjson.Marshal(val, val.Type())
   340→			if err != nil {
   341→				return err
   342→			}
   343→			p.Variables[name] = &variable{
   344→				Value: valJSON,
   345→			}
   346→		}
   347→	}
   348→
   349→	if len(p.Variables) == 0 {
   350→		p.Variables = nil // omit this property if there are no variables to describe
   351→	}
   352→
   353→	return nil
   354→}
