   356→// MarshalResourceChanges converts the provided internal representation of
   357→// ResourceInstanceChangeSrc objects into the public structured JSON changes.
   358→//
   359→// This function is referenced directly from the structured renderer tests, to
   360→// ensure parity between the renderers. It probably shouldn't be used anywhere
   361→// else.
   362→func MarshalResourceChanges(resources []*plans.ResourceInstanceChangeSrc, schemas *terraform.Schemas) ([]ResourceChange, error) {
   363→	var ret []ResourceChange
   364→
   365→	var sortedResources []*plans.ResourceInstanceChangeSrc
   366→	sortedResources = append(sortedResources, resources...)
   367→	sort.Slice(sortedResources, func(i, j int) bool {
   368→		if !sortedResources[i].Addr.Equal(sortedResources[j].Addr) {
   369→			return sortedResources[i].Addr.Less(sortedResources[j].Addr)
   370→		}
   371→		return sortedResources[i].DeposedKey < sortedResources[j].DeposedKey
   372→	})
   373→
   374→	for _, rc := range sortedResources {
   375→		var r ResourceChange
   376→		addr := rc.Addr
   377→		r.Address = addr.String()
   378→		if !addr.Equal(rc.PrevRunAddr) {
   379→			r.PreviousAddress = rc.PrevRunAddr.String()
   380→		}
   381→
   382→		dataSource := addr.Resource.Resource.Mode == addrs.DataResourceMode
   383→		// We create "delete" actions for data resources so we can clean up
   384→		// their entries in state, but this is an implementation detail that
   385→		// users shouldn't see.
   386→		if dataSource && rc.Action == plans.Delete {
   387→			continue
   388→		}
   389→
   390→		schema, _ := schemas.ResourceTypeConfig(
   391→			rc.ProviderAddr.Provider,
   392→			addr.Resource.Resource.Mode,
   393→			addr.Resource.Resource.Type,
   394→		)
   395→		if schema == nil {
   396→			return nil, fmt.Errorf("no schema found for %s (in provider %s)", r.Address, rc.ProviderAddr.Provider)
   397→		}
   398→
   399→		changeV, err := rc.Decode(schema.ImpliedType())
   400→		if err != nil {
   401→			return nil, err
   402→		}
   403→		// We drop the marks from the change, as decoding is only an
   404→		// intermediate step to re-encode the values as json
   405→		changeV.Before, _ = changeV.Before.UnmarkDeep()
   406→		changeV.After, _ = changeV.After.UnmarkDeep()
   407→
   408→		var before, after []byte
   409→		var beforeSensitive, afterSensitive []byte
   410→		var afterUnknown cty.Value
   411→
   412→		if changeV.Before != cty.NilVal {
   413→			before, err = ctyjson.Marshal(changeV.Before, changeV.Before.Type())
   414→			if err != nil {
   415→				return nil, err
   416→			}
   417→			marks := rc.BeforeValMarks
   418→			if schema.ContainsSensitive() {
   419→				marks = append(marks, schema.ValueMarks(changeV.Before, nil)...)
   420→			}
   421→			bs := jsonstate.SensitiveAsBool(changeV.Before.MarkWithPaths(marks))
   422→			beforeSensitive, err = ctyjson.Marshal(bs, bs.Type())
   423→			if err != nil {
   424→				return nil, err
   425→			}
   426→		}
   427→		if changeV.After != cty.NilVal {
   428→			if changeV.After.IsWhollyKnown() {
   429→				after, err = ctyjson.Marshal(changeV.After, changeV.After.Type())
   430→				if err != nil {
   431→					return nil, err
   432→				}
   433→				afterUnknown = cty.EmptyObjectVal
   434→			} else {
   435→				filteredAfter := omitUnknowns(changeV.After)
   436→				if filteredAfter.IsNull() {
   437→					after = nil
   438→				} else {
   439→					after, err = ctyjson.Marshal(filteredAfter, filteredAfter.Type())
   440→					if err != nil {
   441→						return nil, err
   442→					}
   443→				}
   444→				afterUnknown = unknownAsBool(changeV.After)
   445→			}
   446→			marks := rc.AfterValMarks
   447→			if schema.ContainsSensitive() {
   448→				marks = append(marks, schema.ValueMarks(changeV.After, nil)...)
   449→			}

